var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 사장님. 이번에도 전원 코드 뽑힌 걸로 컴퓨터 고장났다고 부른 거면 가만 안 둬.","JPN":"はいはい、またパソコンが壊れたりでもしたの？この前みたいに、電源コードが抜けただけなら承知しないからね。","ENG":"Alright, Boss. You'd better not have called me because you forgot to plug in your computer and thought it was broken.","TWN":"好，老闆。如果你這次叫我來，也是因為把電源線拔掉當成電腦故障的話，我是不會放過你的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 저기, 잠깐 일시 정지. 기. 기기. 기다려 봐.","JPN":"えっ、ちょ、ちょっとタンマ。処理が追いつかないんだけど……","ENG":"Wait, what? Stop right there. S-s-stop.","TWN":"啊，那個，暫停，等，等等，等一下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"방금 뭐라고 했어? 나랑...... 종신계약을 하겠다고?","JPN":"今なんて言ったの？\\nアタシと……終身契約を結ぼうって？","ENG":"What did you just say? You want me to... sign for life?","TWN":"你剛才說什麼？要和我……簽訂終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어, 어어어처구니가 없네 진짜! 안 하던 회사 일을 갑자기 하다가 머리에 버그라도 걸린 거 아냐?! 전두엽을 로맨스 소설로 패치한 거 아니냐고!","JPN":"あ、あ、あ……あり得ないわ！ふざけてるの？珍しく仕事に精を出してると思えば、脳がバグっちゃったんじゃない！？スイーツ思考になるウイルスにでもかかっちゃったみたいね！","ENG":"Geez, what the hell is wrong with you?! Did a bug occur while you were doing your work? Or did you download a romance novel patch?","TWN":"真，真真真是不可理喻！你是不是太久沒工作了，一做事就把腦子燒壞啦？！浪漫小說看太多了你！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 뭐야, 진짜......","JPN":"何なのよ……信じられるわけないじゃない……","ENG":"Bah, seriously!","TWN":"啊，搞什麼，真是的……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저기 말이야...... 델타 세븐에 코 꿰여서 이리저리 끌려 다니니까 되게 작스처럼 보였나 본데, 해커란 녀석들은 기본적으로 너드 기질이 베이스거든?","JPN":"えっと……デルタセブンにあちこち連れまわされてるせいで、陽キャだと思われてるのかもしれないけどね。ハッカーっていうのは、たいてい根っからの陰キャ気質なの。","ENG":"Hey, you may have thought I'm a people person, being dragged around by Delta Seven, but hackers like me are basically nerds.","TWN":"我說……雖然我一直被第七三角洲部隊牽著鼻子走，像個隨和的人。但基本上，被叫作駭客的人都是怪咖喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아직도 모르겠어? 그런 중요한 얘기는 채팅으로 하라고!","JPN":"まだわからないの？\\nそんな大事な話はチャットでしろって言ってるの！","ENG":"Don't you get it? You should tell me important issues like this online!","TWN":"還不懂嗎？這麼重要的事情要在聊天室說啦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아아...... 얼굴이 다 화끈거리네. 졸업 파티 이후로 오랜만이야.","JPN":"ふうぅ……顔から火が出ちゃいそう。こんな気分は卒業パーティー以来ね。","ENG":"Gah! Even my face is hot. I've never felt this way since the graduation party.","TWN":"(臉紅)……從畢業舞會後，我的臉很久沒有這麼紅過了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"계약서나 줘. 얼른 도장 찍어 버리게.","JPN":"さっさと契約書をよこしなさい。こうなったら、勢いでハンコを押してあげるわ。","ENG":"Just give me the contract. I'm going to sign and get it over with.","TWN":"契約書拿來，快點蓋章吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};